#include "AStarPlanner.h"
struct Node{uint8_t idx; uint8_t mask; float load,g,h,f;};
float AStarPlanner::cost(const Appliance& a,bool on,const SolarData& s,const BatteryData& b) const{ if(!on) return a.mandatory?1000:(a.priority+a.userPreference+a.importance)*0.2f; float batt=std::max(0.0f,a.power()-s.power); return batt*0.02f - a.userPreference*2 - a.priority*0.1f - a.importance*2 + a.startupSurge()*0.005f + (b.soc<25?50:0); }
uint8_t AStarPlanner::plan(Appliance* loads,uint8_t count,const SolarData& s,const BatteryData& b,PlannerDecision* out,uint8_t maxOut){ Node open[64]; uint8_t openCount=1; open[0]={0,0,0,0,0,0}; Node best=open[0]; ConstraintGuard guard; while(openCount){ uint8_t bi=0; for(uint8_t i=1;i<openCount;i++) if(open[i].f<open[bi].f) bi=i; Node n=open[bi]; open[bi]=open[--openCount]; if(n.idx>=count){ best=n; break; } for(uint8_t choice=0;choice<2;choice++){ Node c=n; Appliance& a=loads[n.idx]; c.idx++; if(choice){ if(!guard.canRun(a,s,b,n.load)) continue; c.mask|=(1<<n.idx); c.load+=a.startupSurge(); } c.g+=cost(a,choice,s,b); c.h=0; for(uint8_t j=c.idx;j<count;j++) c.h+=std::min(0.0f,cost(loads[j],true,s,b)); c.f=c.g+c.h; if(openCount<64) open[openCount++]=c; }} uint8_t written=0; for(uint8_t i=0;i<count && written<maxOut;i++){ out[written].applianceId=loads[i].id(); out[written].enabled=(best.mask&(1<<i)); snprintf(out[written].explanation,MAX_TEXT,"%s %s because solar usage, battery reserve, priority, preference, usefulness and surge constraints were evaluated by A*.",loads[i].name(),out[written].enabled?"enabled":"rejected"); written++; } return written; }
